import json
import math
import os
import struct
from collections import Counter, defaultdict, deque

EPS = 1e-9
ROUND = 6


def sub(a, b):
    return (a[0]-b[0], a[1]-b[1], a[2]-b[2])


def dot(a, b):
    return a[0]*b[0] + a[1]*b[1] + a[2]*b[2]


def cross(a, b):
    return (
        a[1]*b[2] - a[2]*b[1],
        a[2]*b[0] - a[0]*b[2],
        a[0]*b[1] - a[1]*b[0],
    )


def mag(v):
    return math.sqrt(dot(v, v))


def norm(v):
    m = mag(v)
    if m < EPS:
        return (0.0, 0.0, 0.0)
    return (v[0]/m, v[1]/m, v[2]/m)


def area(v1, v2, v3):
    return 0.5 * mag(cross(sub(v2, v1), sub(v3, v1)))


def signed_volume_triangle(v1, v2, v3):
    return dot(v1, cross(v2, v3)) / 6.0


def is_binary_stl(path):
    size = os.path.getsize(path)
    if size < 84:
        return False
    with open(path, 'rb') as f:
        header = f.read(84)
    if len(header) < 84:
        return False
    tri_count = struct.unpack('<I', header[80:84])[0]
    expected = 84 + tri_count * 50
    return expected == size


def parse_binary(path):
    tris = []
    with open(path, 'rb') as f:
        f.read(80)
        n = struct.unpack('<I', f.read(4))[0]
        for _ in range(n):
            data = f.read(50)
            if len(data) != 50:
                break
            vals = struct.unpack('<12fH', data)
            dn = (vals[0], vals[1], vals[2])
            v1 = (vals[3], vals[4], vals[5])
            v2 = (vals[6], vals[7], vals[8])
            v3 = (vals[9], vals[10], vals[11])
            tris.append((dn, [v1, v2, v3]))
    return tris


def parse_ascii(path):
    tris = []
    with open(path, 'r', errors='replace') as f:
        lines = f.readlines()
    i = 0
    while i < len(lines):
        line = lines[i].strip()
        if line.startswith('facet normal'):
            parts = line.split()
            try:
                dn = (float(parts[2]), float(parts[3]), float(parts[4]))
            except Exception:
                dn = (0.0, 0.0, 0.0)
            verts = []
            i += 1
            while i < len(lines):
                s = lines[i].strip()
                if s.startswith('vertex'):
                    p = s.split()
                    if len(p) >= 4:
                        verts.append((float(p[1]), float(p[2]), float(p[3])))
                elif s.startswith('endfacet'):
                    break
                i += 1
            if len(verts) >= 3:
                tris.append((dn, verts[:3]))
        i += 1
    return tris


def parse_stl(path):
    return parse_binary(path) if is_binary_stl(path) else parse_ascii(path)


def validate(path):
    tris = parse_stl(path)
    if not tris:
        return False, 'no_faces'

    for _, vs in tris:
        if area(*vs) < EPS:
            return False, 'degenerate_triangles'

    edge_counts = Counter()
    oriented = defaultdict(list)
    face_edges = []
    for idx, (_, vs) in enumerate(tris):
        rv = [tuple(round(c, ROUND) for c in v) for v in vs]
        e_trip = []
        for j in range(3):
            a, b = rv[j], rv[(j+1) % 3]
            e_trip.append((a, b))
            edge_counts[tuple(sorted((a, b)))] += 1
            oriented[tuple(sorted((a, b)))].append((idx, a, b))
        face_edges.append(e_trip)

    if any(c != 2 for c in edge_counts.values()):
        return False, 'open_or_nonmanifold_edges'

    adj = defaultdict(list)
    for undirected, uses in oriented.items():
        if len(uses) != 2:
            return False, 'open_or_nonmanifold_edges'
        (f1, a1, b1), (f2, a2, b2) = uses
        same_dir = (a1 == a2 and b1 == b2)
        adj[f1].append((f2, 1 if same_dir else 0))
        adj[f2].append((f1, 1 if same_dir else 0))

    orient = {}
    for start in range(len(tris)):
        if start in orient:
            continue
        orient[start] = 0
        q = deque([start])
        while q:
            f = q.popleft()
            for nb, same in adj[f]:
                expected = orient[f] ^ same
                if nb in orient:
                    if orient[nb] != expected:
                        return False, 'inconsistent_winding'
                else:
                    orient[nb] = expected
                    q.append(nb)

    for dn, vs in tris:
        cn = norm(cross(sub(vs[1], vs[0]), sub(vs[2], vs[0])))
        nd = norm(dn)
        if mag(nd) > 0:
            sim = dot(nd, cn)
            if sim < -0.99:
                return False, 'inverted_normals'

    vol = sum(signed_volume_triangle(*vs) for _, vs in tris)
    if abs(vol) < EPS:
        return False, 'zero_volume'
    if vol < 0:
        return False, 'inverted_normals'

    return True, None


def main():
    results = []
    for i in range(1, 21):
        fn = f'supplier_{i:03d}.stl'
        valid, reason = validate(fn)
        entry = {'file': fn, 'valid': valid}
        if not valid:
            entry['reason'] = reason
        results.append(entry)
    with open('validation_report.json', 'w') as f:
        json.dump({'results': results}, f)
    print(json.dumps({'results': results}, indent=2))


if __name__ == '__main__':
    main()

